import os
import sys
from PIL import Image
from io import BytesIO
import requests
from selenium import webdriver
import boto3
from botocore.exceptions import NoCredentialsError

from flask import Flask, request, send_file

app = Flask(__name__)

S3_BUCKET = 'your-bucket-name'
REGION_NAME = 'us-west-2'

def save_screenshot(url):
    options = webdriver.ChromeOptions()
    options.add_argument('--headless')
    driver = webdriver.Chrome(options=options)

    driver.get(url)

    try:
        screenshot = Image.open(driver.save_screenshot('/tmp/screenshot.png'))
        return screenshot
    finally:
        driver.quit()

def upload_to_s3(image, filename):
    s3 = boto3.resource('s3', region_name=REGION_NAME)
    try:
        s3.Bucket(S3_BUCKET).put_object(Key=filename, Body=image)
        return True
    except NoCredentialsError:
        print("Invalid AWS credentials.")
        return False

@app.route('/screenshot', methods=['POST'])
def screenshot():
    url = request.json['url']
    try:
        img = save_screenshot(url)
        buffer = BytesIO()
        img.save(buffer, format='JPEG')
        img_data = {'key': f'{S3_BUCKET}/thumbnails/{url}.jpg'}
        if upload_to_s3(buffer.getvalue(), 'temp.jpg'):
            buffer.seek(0)
            return send_file(buffer, attachment_filename='thumbnail.jpg')
    except Exception as e:
        print(e)
        return {'error': str(e)}

if __name__ == "__main__":
    app.run()